#define MAX_THREADS_PER_BLOCK 256

#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <iostream>
#include <string>
#include <cstring>

#include <cuda_runtime.h>

struct Node {
    int starting;
    int no_of_edges;
};

int work_group_size = 512;

__global__ void BFS_1(const Node* g_graph_nodes,
					const int* g_graph_edges, 
					char* g_graph_mask, 
					char* g_updating_graph_mask, 
					char* g_graph_visited, 
					int* g_cost, 
					const int no_of_nodes){
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if( tid < no_of_nodes && g_graph_mask[tid]){
		g_graph_mask[tid] = false;
		int start = g_graph_nodes[tid].starting;
		int end = start + g_graph_nodes[tid].no_of_edges;
		for(int i = start; i < end; i++){
			int id = g_graph_edges[i];
			if(!g_graph_visited[id]){
				g_cost[id] = g_cost[tid] + 1;
				g_updating_graph_mask[id] = true;
			}
		}
	}	
}

__global__ void BFS_2(char* g_graph_mask, 
					char* g_updating_graph_mask, 
					char* g_graph_visited, 
					char* g_over,
					const int no_of_nodes) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if( tid < no_of_nodes && g_updating_graph_mask[tid]){
		g_graph_mask[tid] = true;
		g_graph_visited[tid] = true;
		*g_over = true;
		g_updating_graph_mask[tid] = false;
	}
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop = false;
        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                int start = h_graph_nodes[tid].starting;
                int end = start + h_graph_nodes[tid].no_of_edges;
                for(int i = start; i < end; i++) {
                    int id = h_graph_edges[i];	
                    if(!h_graph_visited[id]) {	
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while(stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost)
{
    char h_over;
    Node *d_graph_nodes = nullptr;
    int *d_graph_edges = nullptr;
    char *d_graph_mask = nullptr;
    char *d_updating_graph_mask = nullptr;
    char *d_graph_visited = nullptr;
    int *d_cost = nullptr;
    char *d_over = nullptr;

    try {
        // Allocate device memory
        cudaMalloc((void**)&d_graph_nodes, no_of_nodes * sizeof(Node));
        cudaMalloc((void**)&d_graph_edges, edge_list_size * sizeof(int));
        cudaMalloc((void**)&d_graph_mask, no_of_nodes * sizeof(char));
        cudaMalloc((void**)&d_updating_graph_mask, no_of_nodes * sizeof(char));
        cudaMalloc((void**)&d_graph_visited, no_of_nodes * sizeof(char));
        cudaMalloc((void**)&d_cost, no_of_nodes * sizeof(int));
        cudaMalloc((void**)&d_over, sizeof(char));

        // Copy data to device
        cudaMemcpy(d_graph_nodes, h_graph_nodes, no_of_nodes * sizeof(Node), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_edges, h_graph_edges, edge_list_size * sizeof(int), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_mask, h_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_cost, h_cost, no_of_nodes * sizeof(int), cudaMemcpyHostToDevice);

        int num_blocks = (no_of_nodes + work_group_size - 1) / work_group_size;

        do {
            h_over = false;
            cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice);

            BFS_1<<<num_blocks, work_group_size>>>(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask, d_graph_visited, d_cost, no_of_nodes);
            cudaDeviceSynchronize();

            BFS_2<<<num_blocks, work_group_size>>>(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);
            cudaDeviceSynchronize();

            cudaMemcpy(&h_over, d_over, sizeof(char), cudaMemcpyDeviceToHost);
        } while(h_over);

        cudaMemcpy(h_cost, d_cost, no_of_nodes * sizeof(int), cudaMemcpyDeviceToHost);

        // Free device memory
        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);
    } catch (...) {
        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);
        throw;
    }
}

void Usage(int argc, char**argv)
{
    fprintf(stderr,"Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

